}

#[divan::bench]
fn bench_merge_icms_totals(bencher: divan::Bencher) {
    let source = IcmsTotals::new()
        .v_bc(Cents(10000))
        .v_icms(Cents(1800))
        .v_bc_st(Cents(5000))
        .v_st(Cents(900))
        .v_fcp(Cents(200))
        .v_fcp_st(Cents(100));
    bencher.bench(|| {
        let mut target = create_icms_totals();
        merge_icms_totals(&mut target, divan::black_box(&source));
        target
    });
}

#[divan::bench]
fn bench_merge_icms_totals_10_items(bencher: divan::Bencher) {
    let source = IcmsTotals::new()
        .v_bc(Cents(10000))
        .v_icms(Cents(1800))
        .v_fcp(Cents(200));
    bencher.bench(|| {
        let mut target = create_icms_totals();
        for _ in 0..10 {
            merge_icms_totals(&mut target, divan::black_box(&source));
        }
        target
    });
}

