                    ]),
                ),
                tag(
                    "imposto",
                    &[],
                    TagContent::Children(vec![tag(
                        "ICMS",
                        &[],
                        TagContent::Children(vec![tag(
                            "ICMS00",
                            &[],
                            TagContent::Children(vec![
                                tag("orig", &[], "0".into()),
                                tag("CST", &[], "00".into()),
                                tag("modBC", &[], "0".into()),
                                tag("vBC", &[], "150.00".into()),
                                tag("pICMS", &[], "18.0000".into()),
                                tag("vICMS", &[], "27.00".into()),
