        // enderDest
        let ee = &self.ender_dest_fields;
        if ee.get("xLgr").is_some() {
            let mut ec = Vec::new();
            add_child(&mut ec, "xLgr", ee.get("xLgr").map(|s| s.as_str()));
            add_child(&mut ec, "nro", ee.get("nro").map(|s| s.as_str()));
            if let Some(v) = ee.get("xCpl") {
                if !v.is_empty() {
                    add_child_str(&mut ec, "xCpl", v);
