//! Error types for all fiscal operations.

use thiserror::Error;

/// The primary error type returned by all public functions in `fiscal-core`,
/// `fiscal-crypto`, and `fiscal-sefaz`.
///
/// All variants are `#[non_exhaustive]` so new error cases can be added in
/// future releases without breaking downstream `match` arms.
#[derive(Debug, Error, PartialEq, Eq)]
#[non_exhaustive]
pub enum FiscalError {
    /// A tax data field contains an illegal value (e.g. malformed CNPJ, wrong
    /// field length, invalid access-key format).
    #[error("Invalid tax data: {0}")]
    InvalidTaxData(String),

    /// An ICMS CST code is not recognised by the current tax computation module.
    #[error("Unsupported ICMS CST: {0}")]
    UnsupportedIcmsCst(String),

    /// An ICMS CSOSN code is not recognised by the current tax computation module.
    #[error("Unsupported ICMS CSOSN: {0}")]
    UnsupportedIcmsCsosn(String),

    /// A required XML field is absent. The `field` member names the missing tag.
    #[error("Required tax field \"{field}\" is missing")]
    MissingRequiredField {
        /// Name of the required XML tag or parameter that was absent.
        field: String,
    },

    /// A GTIN barcode value is malformed or has an invalid check digit.
    #[error("Invalid GTIN: {0}")]
    InvalidGtin(String),

    /// An error occurred while building or serialising an XML document.
    #[error("XML generation failed: {0}")]
    XmlGeneration(String),

    /// An error occurred while parsing an XML document.
    #[error("XML parsing failed: {0}")]
    XmlParsing(String),

    /// SEFAZ returned a rejection status code for a submitted document or event.
    #[error("SEFAZ rejected: [{code}] {message}")]
    SefazRejection {
        /// SEFAZ status code (`cStat`), e.g. `"301"`.
        code: String,
        /// Human-readable rejection message (`xMotivo`).
        message: String,
    },

    /// An error occurred while loading, parsing, or using a PKCS#12 certificate.
    #[error("Certificate error: {0}")]
    Certificate(String),

    /// A two-letter state abbreviation (UF) or IBGE numeric code was not found
    /// in the lookup table.
    #[error("Invalid state code: {0}")]
    InvalidStateCode(String),

    /// An error occurred while activating, loading, or applying contingency mode.
    #[error("Contingency error: {0}")]
    Contingency(String),

    /// A TXT document is structurally invalid or references an unsupported layout.
    #[error("Invalid TXT: {0}")]
    InvalidTxt(String),

    /// The supplied document is not of the expected type (e.g. not a valid
    /// NFe TXT header).
    #[error("Wrong document: {0}")]
    WrongDocument(String),

    /// An HTTP or network-level error occurred during SEFAZ communication.
    #[error("Network error: {0}")]
    Network(String),
}

//! Formatting helpers for monetary amounts, rates, and decimal numbers.
//!
//! All functions accept raw integer representations — cents for monetary values
//! and scaled integers for rates — and return formatted `String`s suitable for
//! insertion into NF-e XML elements.

/// Format a cents integer to a decimal string with the given number of decimal places.
///
/// # Examples
///
/// ```
/// use fiscal_core::format_utils::format_cents;
/// assert_eq!(format_cents(1050, 2), "10.50");
/// assert_eq!(format_cents(100000, 10), "1000.0000000000");
/// ```
pub fn format_cents(cents: i64, decimal_places: usize) -> String {
    let divisor = 100.0_f64;
    let value = cents as f64 / divisor;
    format!("{value:.decimal_places$}")
}

/// Format a cents integer to a decimal string with 2 decimal places.
///
/// # Examples
///
/// ```
/// use fiscal_core::format_utils::format_cents_2;
/// assert_eq!(format_cents_2(1050), "10.50");
/// assert_eq!(format_cents_2(0), "0.00");
/// ```
pub fn format_cents_2(cents: i64) -> String {
    format_cents(cents, 2)
}

/// Format a cents integer to a decimal string with 10 decimal places (for unit prices).
///
/// # Examples
///
/// ```
/// use fiscal_core::format_utils::format_cents_10;
/// assert_eq!(format_cents_10(100000), "1000.0000000000");
/// ```
pub fn format_cents_10(cents: i64) -> String {
    format_cents(cents, 10)
}

/// Format a floating-point number with `decimal_places` decimal places.
///
/// # Examples
///
/// ```
/// use fiscal_core::format_utils::format_decimal;
/// assert_eq!(format_decimal(3.14159, 2), "3.14");
/// ```
pub fn format_decimal(value: f64, decimal_places: usize) -> String {
    format!("{value:.decimal_places$}")
}

/// Format a rate stored as hundredths of a percent to a decimal string.
///
/// For example, `1800` (= 18%) with 4 decimal places → `"18.0000"`.
///
/// # Examples
///
/// ```
/// use fiscal_core::format_utils::format_rate;
/// assert_eq!(format_rate(1800, 4), "18.0000");
/// assert_eq!(format_rate(750, 2), "7.50");
/// ```
pub fn format_rate(hundredths: i64, decimal_places: usize) -> String {
    let value = hundredths as f64 / 100.0;
    format!("{value:.decimal_places$}")
}

/// Format a rate (stored as hundredths) with 4 decimal places.
///
/// # Examples
///
/// ```
/// use fiscal_core::format_utils::format_rate_4;
/// assert_eq!(format_rate_4(1800), "18.0000");
/// ```
pub fn format_rate_4(hundredths: i64) -> String {
    format_rate(hundredths, 4)
}

/// Format a PIS/COFINS rate stored as `value × 10 000` to a 4-decimal string.
///
/// For example, `16500` (= 1.65%) → `"1.6500"`.
///
/// # Examples
///
/// ```
/// use fiscal_core::format_utils::format_rate4;
/// assert_eq!(format_rate4(16500), "1.6500");
/// ```
pub fn format_rate4(value: i64) -> String {
    let v = value as f64 / 10000.0;
    format!("{v:.4}")
}

/// Format an optional cents value to a decimal string, returning `None` when the
/// input is `None`.
pub fn format_cents_or_none(cents: Option<i64>, decimal_places: usize) -> Option<String> {
    cents.map(|c| format_cents(c, decimal_places))
}

/// Format an optional cents value to a decimal string, defaulting to `"0.00"` (or
/// `"0.` + `n` zeros`"`) when the input is `None`.
pub fn format_cents_or_zero(cents: Option<i64>, decimal_places: usize) -> String {
    match cents {
        Some(c) => format_cents(c, decimal_places),
        None => format_cents(0, decimal_places),
    }
}

/// Format an optional `rate4` value (scaled by 10 000) to a 4-decimal string,
/// defaulting to `"0.0000"` when the input is `None`.
pub fn format_rate4_or_zero(value: Option<i64>) -> String {
    match value {
        Some(v) => format_rate4(v),
        None => "0.0000".to_string(),
    }
}

use crate::FiscalError;

/// Validate a GTIN-8/12/13/14 barcode number.
///
/// - Empty string and `"SEM GTIN"` are considered valid (exempt).
/// - Valid GTIN-8/12/13/14 with correct check digit returns `Ok(true)`.
/// - Non-numeric input or invalid check digit returns `Err`.
///
/// # Examples
///
/// ```
/// use fiscal_core::gtin::is_valid_gtin;
///
/// assert_eq!(is_valid_gtin(""), Ok(true));
/// assert_eq!(is_valid_gtin("SEM GTIN"), Ok(true));
/// assert!(is_valid_gtin("ABC").is_err());
/// ```
///
/// # Errors
///
/// Returns `Err` if:
/// - The input contains non-numeric characters
/// - The length is not 8, 12, 13, or 14
/// - The check digit is invalid
pub fn is_valid_gtin(gtin: &str) -> Result<bool, FiscalError> {
    if gtin.is_empty() || gtin == "SEM GTIN" {
        return Ok(true);
    }

    if gtin.chars().any(|c| !c.is_ascii_digit()) {
        return Err(FiscalError::InvalidGtin(format!(
            "GTIN must contain only digits: \"{gtin}\" is not valid."
        )));
    }

    let len = gtin.len();
    if len != 8 && len != 12 && len != 13 && len != 14 {
        return Err(FiscalError::InvalidGtin(format!(
            "GTIN must be 8, 12, 13, or 14 digits. Got {len} digits."
        )));
    }

    let expected_dv = calculate_check_digit(gtin)?;
    let actual_dv = gtin.as_bytes()[len - 1] - b'0';

    if actual_dv != expected_dv {
        return Err(FiscalError::InvalidGtin(format!(
            "GTIN \"{gtin}\" has an invalid check digit."
        )));
    }

    Ok(true)
}

/// Calculate the GTIN check digit using the standard algorithm.
///
/// Works for GTIN-8, GTIN-12, GTIN-13, and GTIN-14.
/// The input must include the check digit position (full barcode).
///
/// # Errors
///
/// Returns `Err` if the input contains non-digit characters.
pub fn calculate_check_digit(gtin: &str) -> Result<u8, FiscalError> {
    let len = gtin.len();
    if len < 2 {
        return Err(FiscalError::InvalidGtin(
            "GTIN must have at least 2 digits".to_string(),
        ));
    }

    // Pad the digits (excluding last) to 15 positions, left-padded with zeros
    let without_check = &gtin[..len - 1];
    let padded = format!("{:0>15}", without_check);

    let mut total: u32 = 0;
    for (pos, ch) in padded.bytes().enumerate() {
        let val = (ch - b'0') as u32;
        // Alternating multiplier: positions 0,2,4... get x1; positions 1,3,5... get x3
        let multiplier = ((pos + 1) % 2) * 2 + 1;
        total += multiplier as u32 * val;
    }

    let dv = (10 - (total % 10)) % 10;
    Ok(dv as u8)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn calculate_check_digit_too_short() {
        let err = calculate_check_digit("1").unwrap_err();
        assert!(matches!(err, FiscalError::InvalidGtin(_)));
    }

    #[test]
    fn calculate_check_digit_single_digit() {
        let err = calculate_check_digit("0").unwrap_err();
        assert!(matches!(err, FiscalError::InvalidGtin(_)));
    }

    #[test]
    fn calculate_check_digit_valid_gtin13() {
        // 7891000315507 — check digit is 7
        let dv = calculate_check_digit("7891000315507").unwrap();
        assert_eq!(dv, 7);
    }
}

//! Core types, tax computation, and XML generation for Brazilian fiscal documents.
//!
//! `fiscal-core` is the foundation crate of the `fiscal-rs` workspace. It contains:
//!
//! - **Data types** ([`types`], [`newtypes`]) — strongly-typed structs and newtypes for
//!   NF-e / NFC-e document data, validated at construction time.
//! - **Tax computation** ([`tax_icms`], [`tax_pis_cofins_ipi`], [`tax_issqn`], [`tax_is`]) —
//!   build XML fragments for each Brazilian tax group and accumulate invoice totals.
//! - **XML builder** ([`xml_builder`]) — typestate builder for assembling a complete,
//!   schema-compliant NF-e / NFC-e XML document.
//! - **Protocol helpers** ([`complement`], [`contingency`], [`qrcode`]) — attach SEFAZ
//!   authorization protocols, manage contingency mode, and build NFC-e QR codes.
//! - **Utilities** ([`format_utils`], [`xml_utils`], [`gtin`], [`state_codes`],
//!   [`status_codes`], [`constants`]) — formatting, XML escaping, GTIN validation,
//!   IBGE state code lookups, and SEFAZ status-code constants.
//! - **Conversion** ([`convert`], [`standardize`]) — TXT-to-XML converter and
//!   XML type identification / JSON conversion.
//! - **Traits** ([`traits`]) — sealed `TaxCalculation` and `XmlSerializable` traits.

