//! Access key (chave de acesso) generation for NF-e/NFC-e.
//!
//! An access key is a 44-digit numeric string that uniquely identifies
//! a Brazilian fiscal document. Layout:
//!
//! ```text
//! cUF(2) + AAMM(4) + CNPJ(14) + mod(2) + serie(3) + nNF(9)
//! + tpEmis(1) + cNF(8) + cDV(1) = 44 digits
//! ```

use crate::FiscalError;
use crate::types::AccessKeyParams;

/// Build the 44-digit access key from its component parts.
///
/// Concatenates all parts with proper padding, computes the mod-11 check
/// digit, and returns the complete 44-digit key.
///
/// # Errors
///
/// Returns [`FiscalError::XmlGeneration`] if the resulting base does not
/// have exactly 43 digits (indicating malformed input parameters).
pub fn build_access_key(params: &AccessKeyParams) -> Result<String, FiscalError> {
    let base = format!(
        "{cuf:0>2}{aamm}{cnpj:0>14}{model:0>2}{serie:0>3}{nnf:0>9}{tp_emis}{cnf:0>8}",
        cuf = params.state_code,
        aamm = params.year_month,
        cnpj = params.tax_id,
        model = params.model.as_str(),
        serie = params.series,
        nnf = params.number,
        tp_emis = params.emission_type.as_str(),
        cnf = params.numeric_code,
    );

    if base.len() != 43 {
        return Err(FiscalError::XmlGeneration(format!(
            "Access key base must be 43 digits, got {} (\"{}\")",
            base.len(),
            base
        )));
    }

    let check_digit = calculate_mod11(&base);
    Ok(format!("{base}{check_digit}"))
}

/// Calculate the mod-11 check digit used in Brazilian fiscal documents.
///
/// Weights cycle 2→9 from right to left. If the remainder after `% 11`
/// is less than 2 the digit is 0; otherwise it is `11 - remainder`.
pub fn calculate_mod11(digits: &str) -> u8 {
    let mut sum: u32 = 0;
    let mut weight: u32 = 2;

    for ch in digits.bytes().rev() {
        let val = (ch - b'0') as u32;
        sum += val * weight;
        weight = if weight >= 9 { 2 } else { weight + 1 };
    }

    let remainder = sum % 11;
    if remainder < 2 {
        0
    } else {
        (11 - remainder) as u8
    }
}

/// Generate an 8-digit random numeric code for the access key.
pub fn generate_numeric_code() -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    let nanos = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .subsec_nanos();
    let code = (nanos ^ (nanos >> 16)) % 100_000_000;
    format!("{code:08}")
}

/// Format a `DateTime<FixedOffset>` as YYMM for the access key.
pub fn format_year_month(dt: &chrono::DateTime<chrono::FixedOffset>) -> String {
    format!("{}{:02}", &dt.format("%y"), dt.format("%m"))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn mod11_known_values() {
        let base = "4325030412345678901255001000000001100000001";
        let dv = calculate_mod11(base);
        let full = format!("{base}{dv}");
        assert_eq!(full.len(), 44);
    }

    #[test]
    fn mod11_all_zeros() {
        let dv = calculate_mod11("0000000000000000000000000000000000000000000");
        assert_eq!(dv, 0);
    }
}

//! Typestate invoice builder for NF-e / NFC-e XML generation.
//!
//! ```text
//! InvoiceBuilder::new(issuer, env, model)   // Draft
//!     .series(1)
//!     .invoice_number(42)
//!     .add_item(item)
//!     .recipient(recipient)
//!     .payments(vec![payment])
//!     .build()?                              // Built
//!     .sign_with(|xml| sign(xml))?           // Signed
//!     .signed_xml()                          // &str
//! ```
//!
//! The typestate pattern ensures at compile time that `xml()` / `access_key()`
//! are only available after a successful `build()`, and `signed_xml()` is only
//! available after a successful `sign_with()`.

use std::marker::PhantomData;

use chrono::{DateTime, FixedOffset};

use crate::FiscalError;
use crate::newtypes::Cents;
use crate::types::*;

// ── Typestate markers ────────────────────────────────────────────────────────

/// Marker: invoice is being assembled (setters available, no XML yet).
pub struct Draft;

/// Marker: invoice has been built (XML and access key available, no setters).
pub struct Built;

/// Marker: invoice has been signed (signed XML available).
pub struct Signed;

// ── Builder ──────────────────────────────────────────────────────────────────

/// Typestate builder for NF-e / NFC-e XML documents.
///
/// In the [`Draft`] state all setters are available.
/// Calling [`build()`](InvoiceBuilder::build) validates the data and
/// transitions to [`Built`], which exposes [`xml()`](InvoiceBuilder::xml)
/// and [`access_key()`](InvoiceBuilder::access_key).
/// Calling [`sign_with()`](InvoiceBuilder::sign_with) on `Built` transitions
/// to [`Signed`], which exposes [`signed_xml()`](InvoiceBuilder::signed_xml).
pub struct InvoiceBuilder<State = Draft> {
    // Required from construction
    issuer: IssuerData,
    environment: SefazEnvironment,
    model: InvoiceModel,
    schema_version: SchemaVersion,

    // Defaults provided, overridable
    series: u32,
    invoice_number: u32,
    emission_type: EmissionType,
    issued_at: DateTime<FixedOffset>,
    operation_nature: String,

    // Accumulated during Draft
    items: Vec<InvoiceItemData>,
    recipient: Option<RecipientData>,
    payments: Vec<PaymentData>,
    change_amount: Option<Cents>,
    payment_card_details: Option<Vec<PaymentCardDetail>>,
    contingency: Option<ContingencyData>,
    exit_at: Option<DateTime<FixedOffset>>,

    // IDE overrides
    operation_type: Option<u8>,
    purpose_code: Option<u8>,
    destination_indicator: Option<String>,
    intermediary_indicator: Option<String>,
    emission_process: Option<String>,
    consumer_type: Option<String>,
    buyer_presence: Option<String>,
    print_format: Option<String>,
    ver_proc: Option<String>,
    references: Option<Vec<ReferenceDoc>>,

    // Optional groups
    transport: Option<TransportData>,
    billing: Option<BillingData>,
    withdrawal: Option<LocationData>,
    delivery: Option<LocationData>,
    authorized_xml: Option<Vec<AuthorizedXml>>,
    additional_info: Option<AdditionalInfo>,
    intermediary: Option<IntermediaryData>,
    ret_trib: Option<RetTribData>,
    tech_responsible: Option<TechResponsibleData>,
    purchase: Option<PurchaseData>,
    export: Option<ExportData>,
    issqn_tot: Option<IssqnTotData>,
    cana: Option<CanaData>,
    agropecuario: Option<AgropecuarioData>,
    compra_gov: Option<CompraGovData>,
    pag_antecipado: Option<PagAntecipadoData>,
    is_tot: Option<crate::tax_ibs_cbs::IsTotData>,
    ibs_cbs_tot: Option<crate::tax_ibs_cbs::IbsCbsTotData>,

    // ASCII sanitization
    only_ascii: bool,
    calculation_method: crate::types::CalculationMethod,

    // Present only after build
    result_xml: Option<String>,
    result_access_key: Option<String>,

    // Present only after sign
    result_signed_xml: Option<String>,

    _state: PhantomData<State>,
}

