    fn v_tot_trib_propagated_to_result() {
        let item = sample_item().v_tot_trib(Cents(1234));
        let data = sample_build_data();
        let result = build_det(&item, &data).expect("build_det should succeed");

        assert_eq!(result.v_tot_trib, 1234);
    }

    // ── xPed ────────────────────────────────────────────────────────────

    #[test]
    fn x_ped_produces_correct_xml() {
        let item = sample_item().x_ped("PEDIDO-001");
        let data = sample_build_data();
        let result = build_det(&item, &data).expect("build_det should succeed");

        assert!(result.xml.contains("<xPed>PEDIDO-001</xPed>"));
    }

    // ── infAdProd ───────────────────────────────────────────────────────

    #[test]
    fn inf_ad_prod_produces_correct_xml() {
        let item = sample_item().inf_ad_prod("informacao adicional do produto");
        let data = sample_build_data();
        let result = build_det(&item, &data).expect("build_det should succeed");

        assert!(result.xml.contains("<infAdProd>informacao adicional do produto</infAdProd>"));
    }

    // ── ind_deduz_deson ─────────────────────────────────────────────────

    #[test]
    fn ind_deduz_deson_true_when_set_to_1() {
        let item = InvoiceItemData::new(
            1, "001", "Produto", "27101259", "5102", "UN", 1.0,
            Cents(1000), Cents(1000), "40", Rate(0), Cents(0), "99", "99",
        )
        .icms_v_icms_deson(Cents(100))
        .icms_mot_des_icms(1)
        .icms_ind_deduz_deson("1");
        let data = normal_build_data();
        let result = build_det(&item, &data).expect("build_det should succeed");
        assert!(result.ind_deduz_deson);
    }

    #[test]
    fn ind_deduz_deson_false_when_not_set() {
        let item = sample_item();
        let data = sample_build_data();
        let result = build_det(&item, &data).expect("build_det should succeed");
        assert!(!result.ind_deduz_deson);
    }

    // ── orig override ───────────────────────────────────────────────────

    #[test]
    fn custom_orig_used_in_icms() {
        let item = InvoiceItemData::new(
            1, "001", "Produto", "27101259", "5102", "UN", 1.0,
            Cents(1000), Cents(1000), "00", Rate(1800), Cents(180), "99", "99",
        )
        .orig("1");
        let data = normal_build_data();
        let result = build_det(&item, &data).expect("build_det should succeed");

        assert!(result.xml.contains("<orig>1</orig>"));
    }
}

//! Build the `<emit>` (issuer/emitter) group of the NF-e XML.

use super::tax_id::TaxId;
use crate::types::InvoiceBuildData;
use crate::xml_utils::{TagContent, tag};

/// Build the `<emit>` element with issuer data and address.
pub(crate) fn build_emit(data: &InvoiceBuildData) -> String {
    let iss = &data.issuer;
    let tid = TaxId::new(&iss.tax_id);

    let mut children = vec![
        tag(tid.tag_name(), &[], TagContent::Text(&iss.tax_id)),
        tag("xNome", &[], TagContent::Text(&iss.company_name)),
    ];

    if let Some(ref trade_name) = iss.trade_name {
        children.push(tag("xFant", &[], TagContent::Text(trade_name)));
    }

    children.push(tag(
        "enderEmit",
        &[],
        TagContent::Children(build_address_fields(
            &iss.street,
            &iss.street_number,
            iss.address_complement.as_deref(),
            &iss.district,
            &iss.city_code.0,
            &iss.city_name,
            &iss.state_code,
            Some(&iss.zip_code),
            true,
            iss.phone.as_deref(),
        )),
    ));
    children.push(tag("IE", &[], TagContent::Text(&iss.state_tax_id)));

    if let Some(ref iest) = iss.iest {
        children.push(tag("IEST", &[], TagContent::Text(iest)));
    }
    if let Some(ref im) = iss.im {
        children.push(tag("IM", &[], TagContent::Text(im)));
        if let Some(ref cnae) = iss.cnae {
            children.push(tag("CNAE", &[], TagContent::Text(cnae)));
        }
    }

    children.push(tag(
        "CRT",
        &[],
        TagContent::Text(&(iss.tax_regime as u8).to_string()),
    ));

    tag("emit", &[], TagContent::Children(children))
}

/// Build address child tags (xLgr … fone), reused for emit/dest/retirada/entrega.
#[allow(clippy::too_many_arguments)]
pub fn build_address_fields(
    street: &str,
    number: &str,
    complement: Option<&str>,
    district: &str,
    city_code: &str,
    city_name: &str,
    state_code: &str,
    zip_code: Option<&str>,
    include_country: bool,
    phone: Option<&str>,
) -> Vec<String> {
    let mut fields = vec![
        tag("xLgr", &[], TagContent::Text(street)),
        tag("nro", &[], TagContent::Text(number)),
    ];
    if let Some(cpl) = complement {
        fields.push(tag("xCpl", &[], TagContent::Text(cpl)));
    }
    fields.extend([
        tag("xBairro", &[], TagContent::Text(district)),
        tag("cMun", &[], TagContent::Text(city_code)),
        tag("xMun", &[], TagContent::Text(city_name)),
        tag("UF", &[], TagContent::Text(state_code)),
    ]);
    if let Some(cep) = zip_code {
        fields.push(tag("CEP", &[], TagContent::Text(cep)));
    }
    if include_country {
        fields.push(tag("cPais", &[], TagContent::Text("1058")));
        fields.push(tag("xPais", &[], TagContent::Text("Brasil")));
    }
    if let Some(fone) = phone {
        fields.push(tag("fone", &[], TagContent::Text(fone)));
    }
    fields
}

//! Build the `<ide>` (identification) group of the NF-e XML.

use super::tax_id::TaxId;
use crate::types::{InvoiceBuildData, InvoiceModel, ReferenceDoc};
use crate::xml_utils::{TagContent, tag};

/// Format date/time for NF-e (ISO 8601 with Brazil timezone offset).
///
/// SEFAZ rejects UTC `"Z"` suffix — requires explicit offset like `-03:00`.
pub fn format_datetime_nfe(dt: &chrono::DateTime<chrono::FixedOffset>, state_code: &str) -> String {
    let offset = match state_code {
        "AC" => "-05:00",
        "AM" | "RO" | "RR" | "MT" | "MS" => "-04:00",
        _ => "-03:00",
    };
    format!("{}{offset}", dt.format("%Y-%m-%dT%H:%M:%S"))
}

/// Build the `<ide>` element with all identification fields.
pub(crate) fn build_ide(
    data: &InvoiceBuildData,
    state_ibge: &str,
    numeric_code: &str,
    access_key: &str,
) -> String {
    let ref_elements = build_references(data.references.as_deref());

    let dh_emi = format_datetime_nfe(&data.issued_at, &data.issuer.state_code);
    let series_str = data.series.to_string();
    let number_str = data.number.to_string();
    let tp_nf = data.operation_type.unwrap_or(1).to_string();
    let fin_nfe = data.purpose_code.unwrap_or(1).to_string();

    let mut children = vec![
        tag("cUF", &[], TagContent::Text(state_ibge)),
        tag("cNF", &[], TagContent::Text(numeric_code)),
        tag("natOp", &[], TagContent::Text(&data.operation_nature)),
        tag("mod", &[], TagContent::Text(data.model.as_str())),
        tag("serie", &[], TagContent::Text(&series_str)),
        tag("nNF", &[], TagContent::Text(&number_str)),
        tag("dhEmi", &[], TagContent::Text(&dh_emi)),
    ];

    // dhSaiEnt: optional, model 55 only (matching PHP behaviour)
    if data.model == InvoiceModel::Nfe {
        if let Some(ref exit_dt) = data.exit_at {
            let dh_sai_ent = format_datetime_nfe(exit_dt, &data.issuer.state_code);
            children.push(tag("dhSaiEnt", &[], TagContent::Text(&dh_sai_ent)));
        }
    }

    children.extend([
        tag("tpNF", &[], TagContent::Text(&tp_nf)),
        tag(
            "idDest",
            &[],
            TagContent::Text(data.destination_indicator.as_deref().unwrap_or("1")),
        ),
        tag("cMunFG", &[], TagContent::Text(&data.issuer.city_code.0)),
        tag(
            "tpImp",
            &[],
            TagContent::Text(data.print_format.as_deref().unwrap_or("1")),
        ),
        tag("tpEmis", &[], TagContent::Text(data.emission_type.as_str())),
        tag("cDV", &[], TagContent::Text(&access_key[43..44])),
        tag("tpAmb", &[], TagContent::Text(data.environment.as_str())),
        tag("finNFe", &[], TagContent::Text(&fin_nfe)),
        tag(
            "indFinal",
            &[],
            TagContent::Text(data.consumer_type.as_deref().unwrap_or("0")),
        ),
        tag(
            "indPres",
            &[],
            TagContent::Text(data.buyer_presence.as_deref().unwrap_or("0")),
        ),
    ]);

    // indIntermed: only emit when explicitly set (PHP uses false for required,
    // meaning null/empty values are omitted)
    if let Some(ref ind) = data.intermediary_indicator {
        children.push(tag("indIntermed", &[], TagContent::Text(ind)));
    }

    children.extend([
        tag(
            "procEmi",
            &[],
            TagContent::Text(data.emission_process.as_deref().unwrap_or("0")),
        ),
        tag(
            "verProc",
            &[],
            TagContent::Text(data.ver_proc.as_deref().unwrap_or("FinOpenPOS 1.0")),
        ),
    ]);

    // dhCont / xJust: contingency timestamp and justification (matching PHP behaviour)
    if let Some(ref cont) = data.contingency {
        let dh_cont = format_datetime_nfe(&cont.at, &data.issuer.state_code);
        children.push(tag("dhCont", &[], TagContent::Text(&dh_cont)));
        children.push(tag("xJust", &[], TagContent::Text(&cont.reason)));
    }

    children.extend(ref_elements);

    // gCompraGov and gPagAntecipado (PL_010+) go inside <ide> after NFref
    // Only emitted when schema is PL_010 or later (matching PHP: $this->schema > 9)
    if data.schema_version.is_pl010() {
        if let Some(ref cg) = data.compra_gov {
            children.push(super::optional::build_compra_gov(cg));
        }
        if let Some(ref pa) = data.pag_antecipado {
            children.push(super::optional::build_pag_antecipado(pa));
        }
    }

    tag("ide", &[], TagContent::Children(children))
}

/// Build referenced document elements (`<NFref>` inside `<ide>`).
fn build_references(references: Option<&[ReferenceDoc]>) -> Vec<String> {
    let Some(refs) = references else {
        return vec![];
    };

    refs.iter()
        .map(|r| match r {
            ReferenceDoc::Nfe { access_key } => tag(
                "NFref",
                &[],
                TagContent::Children(vec![tag("refNFe", &[], TagContent::Text(access_key))]),
            ),
            ReferenceDoc::Nf {
                state_code,
                year_month,
                tax_id,
                model,
                series,
                number,
            } => tag(
                "NFref",
                &[],
                TagContent::Children(vec![tag(
                    "refNF",
                    &[],
                    TagContent::Children(vec![
                        tag("cUF", &[], TagContent::Text(&state_code.0)),
                        tag("AAMM", &[], TagContent::Text(year_month)),
                        tag("CNPJ", &[], TagContent::Text(tax_id)),
                        tag("mod", &[], TagContent::Text(model)),
                        tag("serie", &[], TagContent::Text(series)),
                        tag("nNF", &[], TagContent::Text(number)),
                    ]),
                )]),
            ),
            ReferenceDoc::Nfp {
                state_code,
                year_month,
                tax_id,
                model,
                series,
                number,
            } => {
                let tid = TaxId::new(tax_id);
                tag(
                    "NFref",
                    &[],
                    TagContent::Children(vec![tag(
                        "refNFP",
                        &[],
                        TagContent::Children(vec![
                            tag("cUF", &[], TagContent::Text(&state_code.0)),
                            tag("AAMM", &[], TagContent::Text(year_month)),
                            tag(tid.tag_name(), &[], TagContent::Text(tax_id)),
                            tag("mod", &[], TagContent::Text(model)),
                            tag("serie", &[], TagContent::Text(series)),
                            tag("nNF", &[], TagContent::Text(number)),
                        ]),
                    )]),
                )
            }
            ReferenceDoc::Cte { access_key } => tag(
                "NFref",
                &[],
                TagContent::Children(vec![tag("refCTe", &[], TagContent::Text(access_key))]),
            ),
            ReferenceDoc::Ecf {
                model,
                ecf_number,
                coo_number,
            } => tag(
                "NFref",
                &[],
                TagContent::Children(vec![tag(
                    "refECF",
                    &[],
                    TagContent::Children(vec![
                        tag("mod", &[], TagContent::Text(model)),
                        tag("nECF", &[], TagContent::Text(ecf_number)),
                        tag("nCOO", &[], TagContent::Text(coo_number)),
                    ]),
                )]),
            ),
        })
        .collect()
}

//! NF-e/NFC-e XML builder module.
//!
//! Provides [`InvoiceBuilder`] — a typestate builder that enforces the
//! invoice lifecycle at compile time:
//!
//! ```text
//! InvoiceBuilder::new(issuer, env, model)   // Draft
//!     .series(1)
//!     .invoice_number(42)
//!     .add_item(item)
//!     .recipient(recipient)
//!     .payments(vec![payment])
//!     .build()?                              // Built
//!     .sign_with(|xml| sign(xml))?           // Signed
//!     .signed_xml()                          // &str
//! ```

pub mod access_key;
mod builder;
pub mod dest;
pub mod det;
pub mod emit;
pub mod ide;
pub mod optional;
pub mod pag;
pub mod tax_id;
pub mod total;
pub mod transp;

pub use access_key::build_access_key;
pub use builder::{Built, Draft, InvoiceBuilder, Signed};

use crate::FiscalError;
use crate::constants::{NFE_NAMESPACE, NFE_VERSION};
use crate::newtypes::IbgeCode;
use crate::state_codes::STATE_IBGE_CODES;
use crate::tax_icms::{create_icms_totals, merge_icms_totals};
use crate::types::{AccessKeyParams, InvoiceBuildData, InvoiceXmlResult};
use crate::xml_utils::{TagContent, tag};

/// Internal XML generation from a fully populated [`InvoiceBuildData`].
///
/// Called by [`InvoiceBuilder::build`]; not part of the public API.
fn generate_xml(data: &InvoiceBuildData) -> Result<InvoiceXmlResult, FiscalError> {
    let state_ibge = STATE_IBGE_CODES
        .get(data.issuer.state_code.as_str())
        .copied()
        .ok_or_else(|| FiscalError::InvalidStateCode(data.issuer.state_code.clone()))?;

    let numeric_code = access_key::generate_numeric_code();
    let year_month = access_key::format_year_month(&data.issued_at);

    let ak_params = AccessKeyParams {
        state_code: IbgeCode(state_ibge.to_string()),
        year_month,
        tax_id: data.issuer.tax_id.clone(),
        model: data.model,
        series: data.series,
        number: data.number,
        emission_type: data.emission_type,
        numeric_code: numeric_code.clone(),
    };

    let access_key = build_access_key(&ak_params)?;
    let inf_nfe_id = format!("NFe{access_key}");

    // Build items and accumulate tax totals
    let mut icms_totals = create_icms_totals();
    let mut total_products: i64 = 0;
    let mut total_ipi: i64 = 0;
    let mut total_pis: i64 = 0;
    let mut total_cofins: i64 = 0;
    let mut total_ii: i64 = 0;
    let mut total_frete: i64 = 0;
    let mut total_seg: i64 = 0;
    let mut total_desc: i64 = 0;
    let mut total_outro: i64 = 0;
    let mut total_tot_trib: i64 = 0;
    let mut total_ipi_devol: i64 = 0;
    let mut total_pis_st: i64 = 0;
    let mut total_cofins_st: i64 = 0;
    let mut any_ind_deduz_deson = false;

    let mut det_elements = Vec::with_capacity(data.items.len());
    for item in &data.items {
        let det_result = det::build_det(item, data)?;
        // Track ind_deduz_deson from any item
        if det_result.ind_deduz_deson {
            any_ind_deduz_deson = true;
        }
        // Only accumulate into totals when indTot == 1 (the default)
        if det_result.ind_tot == 1 {
            total_products += item.total_price.0;
            total_ipi += det_result.v_ipi;
            total_pis += det_result.v_pis;
            total_cofins += det_result.v_cofins;
            total_ii += det_result.v_ii;
            total_frete += det_result.v_frete;
            total_seg += det_result.v_seg;
            total_desc += det_result.v_desc;
            total_outro += det_result.v_outro;
            total_tot_trib += det_result.v_tot_trib;
            total_ipi_devol += det_result.v_ipi_devol;
            total_pis_st += det_result.v_pis_st;
            total_cofins_st += det_result.v_cofins_st;
            merge_icms_totals(&mut icms_totals, &det_result.icms_totals);
        }
        det_elements.push(det_result.xml);
    }

    // Assemble infNFe children in schema order
    let mut inf_children = vec![
        ide::build_ide(data, state_ibge, &numeric_code, &access_key),
        emit::build_emit(data),
    ];

    if let Some(dest_xml) = dest::build_dest(data) {
        inf_children.push(dest_xml);
    }

    if let Some(ref w) = data.withdrawal {
        inf_children.push(optional::build_withdrawal(w));
    }
    if let Some(ref d) = data.delivery {
        inf_children.push(optional::build_delivery(d));
    }
    if let Some(ref auths) = data.authorized_xml {
        for a in auths {
            inf_children.push(optional::build_aut_xml(a));
        }
    }

    inf_children.extend(det_elements);

    // Propagate item-level indDeduzDeson to ICMS totals
    if any_ind_deduz_deson {
        icms_totals.ind_deduz_deson = true;
    }

    inf_children.push(total::build_total(
        total_products,
        &icms_totals,
        &total::OtherTotals {
            v_ipi: total_ipi,
            v_pis: total_pis,
            v_cofins: total_cofins,
            v_ii: total_ii,
            v_frete: total_frete,
            v_seg: total_seg,
            v_desc: total_desc,
            v_outro: total_outro,
            v_tot_trib: total_tot_trib,
            v_ipi_devol: total_ipi_devol,
            v_pis_st: total_pis_st,
            v_cofins_st: total_cofins_st,
        },
        data.ret_trib.as_ref(),
        data.issqn_tot.as_ref(),
        data.is_tot.as_ref(),
        data.ibs_cbs_tot.as_ref(),
        data.schema_version,
        data.calculation_method,
    ));

    inf_children.push(transp::build_transp(data));

    if let Some(ref billing) = data.billing {
        inf_children.push(optional::build_cobr(billing));
    }

    inf_children.push(pag::build_pag(
        &data.payments,
        data.change_amount,
        data.payment_card_details.as_deref(),
    ));

    if let Some(ref intermed) = data.intermediary {
        inf_children.push(optional::build_intermediary(intermed));
    }

    let inf_adic = optional::build_inf_adic(data);
    if !inf_adic.is_empty() {
        inf_children.push(inf_adic);
    }

    if let Some(ref exp) = data.export {
        inf_children.push(optional::build_export(exp));
    }
    if let Some(ref purchase) = data.purchase {
        inf_children.push(optional::build_purchase(purchase));
    }
    if let Some(ref cana) = data.cana {
        inf_children.push(optional::build_cana(cana));
    }
    if let Some(ref tech) = data.tech_responsible {
        inf_children.push(optional::build_tech_responsible_with_key(tech, &access_key));
    }
    // agropecuario — only emitted when schema is PL_010 or later
    // (matching PHP: if ($this->schema < 10) { return; })
    if data.schema_version.is_pl010() {
        if let Some(ref agro) = data.agropecuario {
            inf_children.push(optional::build_agropecuario(agro));
        }
    }

    // Matches PHP sped-nfe: no xmlns on infNFe (inherited from NFe parent),
    // Id before versao (same order as PHP's DOMDocument setAttribute calls)
    let inf_nfe = tag(
        "infNFe",
        &[("Id", &inf_nfe_id), ("versao", NFE_VERSION)],
        TagContent::Children(inf_children),
    );

    let mut xml = format!(
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>{}",
        tag(
            "NFe",
            &[("xmlns", NFE_NAMESPACE)],
            TagContent::Children(vec![inf_nfe])
        ),
    );

    if data.only_ascii {
        xml = crate::sanitize::sanitize_xml_text(&xml);
    }

    Ok(InvoiceXmlResult { xml, access_key })
}

//! Build optional XML groups: cobr, infAdic, infIntermed, exporta, compra,
//! infRespTec, retirada, entrega, autXML.

use super::emit::build_address_fields;
use super::tax_id::TaxId;
use crate::format_utils::format_cents;
use crate::types::*;
use crate::xml_utils::{TagContent, tag};
use base64::Engine as _;

/// Build `<cobr>` (billing) element.
pub fn build_cobr(billing: &BillingData) -> String {
    let fc2 = |c: i64| format_cents(c, 2);
    let mut children = Vec::new();

    if let Some(ref inv) = billing.invoice {
        let mut fat_children = vec![
            tag("nFat", &[], TagContent::Text(&inv.number)),
            tag("vOrig", &[], TagContent::Text(&fc2(inv.original_value.0))),
        ];
        if let Some(disc) = inv.discount_value {
            fat_children.push(tag("vDesc", &[], TagContent::Text(&fc2(disc.0))));
        }
        fat_children.push(tag("vLiq", &[], TagContent::Text(&fc2(inv.net_value.0))));
        children.push(tag("fat", &[], TagContent::Children(fat_children)));
    }

    if let Some(ref installments) = billing.installments {
        for inst in installments {
            children.push(tag(
                "dup",
                &[],
                TagContent::Children(vec![
                    tag("nDup", &[], TagContent::Text(&inst.number)),
                    tag("dVenc", &[], TagContent::Text(&inst.due_date)),
                    tag("vDup", &[], TagContent::Text(&fc2(inst.value.0))),
                ]),
            ));
        }
    }

    tag("cobr", &[], TagContent::Children(children))
}

/// Build `<infAdic>` (additional info) element.
pub(crate) fn build_inf_adic(data: &InvoiceBuildData) -> String {
    let mut notes: Vec<String> = Vec::new();

    if let Some(ref cont) = data.contingency {
        notes.push(format!(
            "Emitida em contingencia ({}). Motivo: {}",
            cont.contingency_type.as_str(),
            cont.reason
        ));
    }

    // PHP does NOT auto-add homologation note to infAdic — removed to match PHP

    let add_info = data.additional_info.as_ref();
    let has_additional = add_info.is_some_and(|a| {
        a.taxpayer_note.is_some()
            || a.tax_authority_note.is_some()
            || a.contributor_obs.as_ref().is_some_and(|v| !v.is_empty())
            || a.fiscal_obs.as_ref().is_some_and(|v| !v.is_empty())
            || a.process_refs.as_ref().is_some_and(|v| !v.is_empty())
    });

    if notes.is_empty() && !has_additional {
        return String::new();
    }

    let mut children = Vec::new();

    // infAdFisco before infCpl per schema
    if let Some(note) = add_info.and_then(|a| a.tax_authority_note.as_ref()) {
        children.push(tag("infAdFisco", &[], TagContent::Text(note)));
    }

    // Merge contingency/env notes with taxpayer note
    if let Some(tn) = add_info.and_then(|a| a.taxpayer_note.as_ref()) {
        notes.push(tn.to_string());
    }
    if !notes.is_empty() {
        children.push(tag("infCpl", &[], TagContent::Text(&notes.join("; "))));
    }

    // obsCont (max 10)
    if let Some(obs_list) = add_info.and_then(|a| a.contributor_obs.as_ref()) {
        for obs in obs_list.iter().take(10) {
            children.push(tag(
                "obsCont",
                &[("xCampo", &obs.field)],
                TagContent::Children(vec![tag("xTexto", &[], TagContent::Text(&obs.text))]),
            ));
        }
    }

    // obsFisco (max 10)
    if let Some(obs_list) = add_info.and_then(|a| a.fiscal_obs.as_ref()) {
        for obs in obs_list.iter().take(10) {
            children.push(tag(
                "obsFisco",
                &[("xCampo", &obs.field)],
                TagContent::Children(vec![tag("xTexto", &[], TagContent::Text(&obs.text))]),
            ));
        }
    }

    // procRef (max 100)
    if let Some(procs) = add_info.and_then(|a| a.process_refs.as_ref()) {
        for p in procs.iter().take(100) {
            let mut proc_children = vec![
                tag("nProc", &[], TagContent::Text(&p.number)),
                tag("indProc", &[], TagContent::Text(&p.origin)),
            ];
            if let Some(tp_ato) = &p.tp_ato {
                proc_children.push(tag("tpAto", &[], TagContent::Text(tp_ato)));
            }
            children.push(tag("procRef", &[], TagContent::Children(proc_children)));
        }
    }

    tag("infAdic", &[], TagContent::Children(children))
}

/// Build `<infIntermed>` element.
