            "<soap:Envelope xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\" ",
            "xmlns:xsd=\"http://www.w3.org/2001/XMLSchema\" ",
            "xmlns:soap=\"http://www.w3.org/2003/05/soap-envelope\">",
            "<soap:Header>",
            "<nfeCabecMsg xmlns=\"http://www.portalfiscal.inf.br/nfe/wsdl/CadConsultaCadastro4\">",
            "<cUF>35</cUF>",
            "<versaoDados>2.00</versaoDados>",
            "</nfeCabecMsg>",
            "</soap:Header>",
            "<soap:Body>",
            "<nfeDadosMsg xmlns=\"http://www.portalfiscal.inf.br/nfe/wsdl/CadConsultaCadastro4\">",
            "<ConsCad xmlns=\"http://www.portalfiscal.inf.br/nfe\" versao=\"2.00\">",
            "<infCons><xServ>CONS-CAD</xServ><UF>SP</UF><CNPJ>11222333000181</CNPJ></infCons>",
            "</ConsCad>",
            "</nfeDadosMsg>",
            "</soap:Body>",
            "</soap:Envelope>",
        );
        assert_eq!(
            envelope, expected,
            "Envelope with header must match PHP sped-nfe format exactly"
        );
    }

    #[test]
    fn envelope_with_header_preserves_body_untouched() {
        let meta = SefazService::ConsultaCadastro.meta();
        let body = "<ConsCad><infCons><xServ>CONS-CAD</xServ><UF>MT</UF><CNPJ>99888777000166</CNPJ></infCons></ConsCad>";
        let envelope = build_envelope_with_header(body, "MT", &meta).unwrap();

        // Body must be preserved exactly
        assert!(envelope.contains(body));
        // MT = cUF 51
        assert!(
            envelope.contains("<cUF>51</cUF>"),
            "Must contain cUF for MT (51)"
        );
    }

    #[test]
    fn envelope_with_header_rejects_invalid_state() {
        let meta = SefazService::ConsultaCadastro.meta();
        let err = build_envelope_with_header("<test/>", "XX", &meta).unwrap_err();
        assert!(matches!(err, FiscalError::InvalidStateCode(_)));
    }

    #[test]
    fn envelope_with_header_header_before_body() {
        let meta = SefazService::ConsultaCadastro.meta();
        let body = "<ConsCad/>";
        let envelope = build_envelope_with_header(body, "RS", &meta).unwrap();

        let header_start = envelope
            .find("<soap:Header>")
            .expect("must have soap:Header");
        let header_end = envelope
            .find("</soap:Header>")
            .expect("must close soap:Header");
        let body_start = envelope.find("<soap:Body>").expect("must have soap:Body");

        assert!(
            header_start < header_end,
            "Header must open before it closes"
        );
        assert!(
            header_end < body_start,
            "Header must close before Body opens"
        );
    }

    #[test]
    fn regular_envelope_still_omits_header() {
        // Verify that the standard build_envelope still has no header
        let meta = SefazService::StatusServico.meta();
        let body = "<consStatServ/>";
        let envelope = build_envelope(body, "SP", &meta).unwrap();
        assert!(
            !envelope.contains("<soap:Header"),
            "Regular envelope must not have soap:Header"
        );
        assert!(
            !envelope.contains("nfeCabecMsg"),
            "Regular envelope must not have nfeCabecMsg"
        );
    }
}

use fiscal_core::FiscalError;
use fiscal_core::types::SefazEnvironment;

/// Production and homologation URLs for a SEFAZ web service.
struct ServiceUrls {
    production: &'static str,
    homologation: &'static str,
}

/// All SEFAZ services for a given authorizer.
struct AuthorizerServices {
    nfe_status_servico: ServiceUrls,
    nfe_autorizacao: ServiceUrls,
    nfe_ret_autorizacao: ServiceUrls,
    nfe_consulta_protocolo: ServiceUrls,
    nfe_inutilizacao: ServiceUrls,
    recepcao_evento: ServiceUrls,
    nfe_consulta_cadastro: Option<ServiceUrls>,
    nfe_distribuicao_dfe: Option<ServiceUrls>,
    csc_nfce: Option<ServiceUrls>,
    recepcao_epec: Option<ServiceUrls>,
    epec_status_servico: Option<ServiceUrls>,
    nfe_consulta_dest: Option<ServiceUrls>,
    nfe_download_nf: Option<ServiceUrls>,
}

impl AuthorizerServices {
    /// Resolve the URL for a given service name and environment.
    fn get_url(&self, service: &str, env: SefazEnvironment) -> Option<&'static str> {
        let urls = match service {
            "NfeStatusServico" => &self.nfe_status_servico,
            "NfeAutorizacao" => &self.nfe_autorizacao,
            "NfeRetAutorizacao" => &self.nfe_ret_autorizacao,
            "NfeConsultaProtocolo" => &self.nfe_consulta_protocolo,
            "NfeInutilizacao" => &self.nfe_inutilizacao,
            "RecepcaoEvento" => &self.recepcao_evento,
            "NfeConsultaCadastro" => {
                return self.nfe_consulta_cadastro.as_ref().and_then(|u| {
                    let url = match env {
                        SefazEnvironment::Production => u.production,
                        SefazEnvironment::Homologation => u.homologation,
                        _ => return None,
                    };
                    if url.is_empty() { None } else { Some(url) }
                });
            }
            "NfeDistribuicaoDFe" => {
                return self.nfe_distribuicao_dfe.as_ref().and_then(|u| {
                    let url = match env {
                        SefazEnvironment::Production => u.production,
                        SefazEnvironment::Homologation => u.homologation,
                        _ => return None,
                    };
                    if url.is_empty() { None } else { Some(url) }
                });
            }
            "CscNFCe" => {
                return self.csc_nfce.as_ref().and_then(|u| {
                    let url = match env {
                        SefazEnvironment::Production => u.production,
                        SefazEnvironment::Homologation => u.homologation,
                        _ => return None,
                    };
                    if url.is_empty() { None } else { Some(url) }
                });
            }
            "RecepcaoEPEC" => {
                return self.recepcao_epec.as_ref().and_then(|u| {
                    let url = match env {
                        SefazEnvironment::Production => u.production,
                        SefazEnvironment::Homologation => u.homologation,
                        _ => return None,
                    };
                    if url.is_empty() { None } else { Some(url) }
                });
            }
            "EPECStatusServico" => {
                return self.epec_status_servico.as_ref().and_then(|u| {
                    let url = match env {
                        SefazEnvironment::Production => u.production,
                        SefazEnvironment::Homologation => u.homologation,
                        _ => return None,
                    };
                    if url.is_empty() { None } else { Some(url) }
                });
            }
            "NfeConsultaDest" => {
                return self.nfe_consulta_dest.as_ref().and_then(|u| {
                    let url = match env {
                        SefazEnvironment::Production => u.production,
                        SefazEnvironment::Homologation => u.homologation,
                        _ => return None,
                    };
                    if url.is_empty() { None } else { Some(url) }
                });
            }
            "NfeDownloadNF" => {
                return self.nfe_download_nf.as_ref().and_then(|u| {
                    let url = match env {
                        SefazEnvironment::Production => u.production,
                        SefazEnvironment::Homologation => u.homologation,
                        _ => return None,
                    };
                    if url.is_empty() { None } else { Some(url) }
                });
            }
            _ => return None,
        };
        Some(match env {
            SefazEnvironment::Production => urls.production,
            SefazEnvironment::Homologation => urls.homologation,
            _ => return None,
        })
    }
}

